"""Utilities for fetching Protection Profiles from the NIAP portal API."""

from __future__ import annotations

import logging
from datetime import date, datetime
from typing import Any

import requests

from sec_certs import constants

logger = logging.getLogger(__name__)


def fetch_niap_pps() -> list[dict[str, Any]]:
    """
    Fetch all public Protection Profiles from the NIAP API.

    Returns a list of dicts with keys:
        pp_id, pp_short_name, pp_name, tech_type, status,
        pp_date, sunset_date, pp_sponsor_id, pp_transition, cc_version
    """
    logger.info("Fetching Protection Profiles from NIAP API: %s", constants.NIAP_PP_API_URL)
    resp = requests.get(constants.NIAP_PP_API_URL, timeout=constants.REQUEST_TIMEOUT)
    resp.raise_for_status()
    data = resp.json()
    logger.info("Fetched %d Protection Profiles from NIAP.", len(data))
    return data


def fetch_niap_pp_files(pp_id: int) -> list[dict[str, Any]]:
    """
    Fetch the list of public files for a given NIAP PP.

    Returns a list of dicts with keys:
        file_id, file_mime_type, file_display_name, file_new_name, file_name, file_label, isFolder
    """
    resp = requests.get(
        constants.NIAP_PP_FILE_API_URL,
        params={"file_type": "protection-profile", "file_type_id": pp_id},
        timeout=constants.REQUEST_TIMEOUT,
    )
    resp.raise_for_status()
    return resp.json()


def _parse_niap_date(value: str | None) -> date | None:
    """Parse an ISO datetime string from the NIAP API into a date, or return None."""
    if not value:
        return None
    try:
        return datetime.fromisoformat(value.replace("Z", "+00:00")).date()
    except (ValueError, AttributeError):
        return None


def _niap_status_to_cc(status: str) -> str:
    """Map NIAP PP status to the CC portal status convention."""
    # NIAP uses "Publishing" for active and "Archived" for archived.
    if status.lower() == "archived":
        return "archived"
    return "active"


def _niap_tech_type_to_cc_category(tech_type: str) -> str:
    """Map NIAP Technology Type to a CC portal category string."""
    return constants.NIAP_TECH_TYPE_TO_CC_CATEGORY.get(tech_type, "Other Devices and Systems")


def _pick_pp_pdf_file(files: list[dict[str, Any]]) -> dict[str, Any] | None:
    """Pick the Protection Profile PDF from a list of NIAP files.

    Filters for PDF files whose label starts with "Protection Profile".
    Returns the first matching file dict, or None if no suitable PDF is found.
    """
    for f in files:
        mime = (f.get("file_mime_type") or "").lower()
        label = (f.get("file_label") or "").lower()
        if mime == "application/pdf" and label.startswith("protection profile"):
            return f
    return None


def get_niap_file_download_url(file_id: int) -> str:
    """Construct a download URL for a NIAP file."""
    return constants.NIAP_PP_FILE_DOWNLOAD_URL + "?file_id=" + str(file_id)


def niap_entry_to_pp_dict(entry: dict[str, Any], files: list[dict[str, Any]] | None = None) -> dict[str, Any]:
    """
    Convert a single NIAP API entry into a dict matching ProtectionProfile.WebData fields.

    This produces a flat dict that can be used to construct a ProtectionProfile.
    If *files* (from fetch_niap_pp_files) is provided, the PP PDF download link
    will be resolved and set as ``pp_link``.
    """
    pp_id = entry["pp_id"]
    pp_date = _parse_niap_date(entry.get("pp_date"))
    sunset_date = _parse_niap_date(entry.get("sunset_date"))
    transition_date = _parse_niap_date(entry.get("pp_transition"))

    niap_url = constants.NIAP_PP_DETAIL_URL.format(pp_id)

    cc_version = entry.get("cc_version", "")
    security_level: set[str] = set()
    if cc_version:
        security_level.add(cc_version)

    # Resolve PP PDF download link from the file list
    pp_link: str | None = None
    if files:
        pp_file = _pick_pp_pdf_file(files)
        if pp_file:
            pp_link = get_niap_file_download_url(pp_file["file_id"])

    return {
        "category": _niap_tech_type_to_cc_category(entry.get("tech_type", "")),
        "status": _niap_status_to_cc(entry.get("status", "Publishing")),
        "is_collaborative": False,
        "name": entry.get("pp_name", ""),
        "version": "",
        "security_level": security_level,
        "not_valid_before": pp_date,
        "not_valid_after": sunset_date,
        "report_link": None,
        "pp_link": pp_link,
        "scheme": "US",
        "maintenances": [],
        # NIAP-specific extra fields
        "niap_id": pp_id,
        "niap_url": niap_url,
        "niap_short_name": entry.get("pp_short_name", ""),
        "niap_sponsor": entry.get("pp_sponsor_id", ""),
        "niap_transition_date": transition_date,
        "source": "niap",
    }
